mapper.select:
select id
from album
where id = #{id}

select a.id, a.title, a.details, a.primary_artist_id, null as action, d.release_date from album a join lateral (select case when (a.details->>'releaseDate') ~ '^\d\d\d\d-\d\d-\d\d$' then (a.details->>'releaseDate')::date end release_date ) as d on true left join artist aa on a.primary_artist_id = aa.id
(a.title ~* #{criteria.searchName} or aa.name ~* #{criteria.searchName})
d.release_date >= #{criteria.dateStart}
and d.release_date <= #{criteria.dateEnd}
a.title
d.release_date
aa.name
${ord.direction.clause}
${ord.nullsOrder.clause}
,a.id
